import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {
    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by encoding it before outputting to the web page
        PrintWriter out = new PrintWriter(System.out);
        out.println("<html>");
        out.println("<head><title>XSS Fixed Page</title></head>");
        out.println("<body>");
        out.println("<h1>Welcome, " + ESAPI.encoder().encodeForHTML(userInput) + "</h1>"); // Encode user input for HTML context
        out.println("</body>");
        out.println("</html>");

        out.flush();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
